#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ull unsigned long long
const int N=1000005,base=233317;
ull tmp[N],hasa[N],hasb;
int n,m,len;
string a,b,sta;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>a>>b;
	n=a.size();
	m=b.size() ;
	a=" "+a;
	b=" "+b;
	tmp[0]=1;
	for(int i=1;i<=m;i++)
	{
		tmp[i]=tmp[i-1]*base;
		hasb=hasb*base+b[i]-'a';
	}
//	cout<<hasb<<"aaa\n";
	for(int i=1;i<=n;i++) sta+=" ";
	for(int i=1;i<=n;i++)
	{
		sta[++len]=a[i];
		hasa[len]=hasa[len-1]*base+a[i]-'a';
//		cout<<i<<"  :   "<<hasa[len]<<"\n";
//		cout<<i<<"  : " <<hasa[len]-hasa[len-m]*tmp[m]<<"\n";
		if(len>=m && hasb==hasa[len]-hasa[len-m]*tmp[m])
		{
//			cout<<i<<" bb\n";
			len-=m;
		}
	}
	for(int i=1;i<=len;i++) cout<<sta[i];
	return 0;
}
